  reward_badge_id,
  is_published,
  user_id
) VALUES (
  'ruta1',
  'La Clave del Barrio',
  'The Key of the Neighborhood',
  '["museo-salsa-obrero","plazoleta-jairo-varela","audiosca-municipal"]'::jsonb,
  240,
  'Esta ruta es una peregrinación al corazón sonoro de Cali, la Capital Mundial de la Salsa. Más que un género musical, aquí la salsa es una religión que se baila y se vive en cada esquina. ''La Clave del Barrio'' te sumerge en la identidad de un pueblo que transformó un ritmo antillano en su propia bandera cultural: desde la habitación donde Carlos Molina guardaba sus primeras fotos, hasta la sala de vinilos donde la Audioteca preserva grabaciones que no existen en ningún otro lugar del mundo. Es un viaje donde el cuerpo no puede evitar moverse y donde entenderás por qué en Cali, la vida tiene su propia clave.',
  'This route is a pilgrimage to the sonic heart of Cali, the World Capital of Salsa. More than a musical genre, salsa here is a religion danced and lived on every corner. ''The Key of the Neighborhood'' immerses you in the identity of a people who transformed an Antillean rhythm into their own cultural flag — from the room where Carlos Molina kept his first photographs to the vinyl hall where the Audioteca preserves recordings that exist nowhere else in the world.',
  'El Barrio Obrero no se anuncia con letreros. Se anuncia con clave. Antes de entrar, escucha: ¿puedes oír el ritmo que late en las paredes de ladrillo? Aquí nació el estilo caleño, no en un estudio de grabación, sino en los solares y bailaderos de esta cuadrícula popular. Hoy vas a leer la historia que no aparece en los libros.',
  'Barrio Obrero doesn''t announce itself with signs. It announces itself with rhythm. Before entering, listen: can you hear the beat pulsing through the brick walls? The Cali style was born here — not in a recording studio, but in the courtyards and dance halls of this working-class grid. Today you will read the history that doesn''t appear in books.',
  '["La salsa caleña es un lenguaje social propio, distinto al modelo neoyorquino.","El Museo de la Salsa es el repositorio fotográfico salsero más antiguo del mundo.","La Audioteca Municipal guarda grabaciones del Pacífico que no existen en ningún otro archivo global."]'::jsonb,
  '["Cali salsa is its own social language, distinct from the New York model.","The Salsa Museum is the world''s oldest salsa photographic repository.","The Municipal Audioteca holds Pacific music recordings that exist in no other global archive."]'::jsonb,
  '[{"tipo":"Música","titulo":"Tu playlist de la ruta","titulo_en":"Your route playlist","descripcion":"Antes de salir, carga en tu teléfono: \"Buenaventura y Caney\" (Grupo Niche), \"Las Caleñas son como las Flores\" (Piper Pimienta) y cualquier álbum de Joe Arroyo. Úsalos como banda sonora entre sitio y sitio — es parte de la experiencia.","descripcion_en":"Before leaving, load on your phone: \"Buenaventura y Caney\" (Grupo Niche), \"Las Caleñas son como las Flores\" (Piper Pimienta), and any Joe Arroyo album. Use them as the soundtrack between sites — it''s part of the experience."},{"tipo":"Vestuario","titulo":"Calzado de barrio","titulo_en":"Neighborhood footwear","descripcion":"El Barrio Obrero es calles de asfalto y aceras estrechas. Usa zapatos planos de suela suave — si vas a dejarte llevar a bailar en algún solar o tienda de vinilos (es probable que pase), los tacones altos serán un obstáculo, no un accesorio.","descripcion_en":"Barrio Obrero is asphalt streets and narrow sidewalks. Wear flat soft-soled shoes — if you get pulled into dancing at a courtyard or vinyl shop (it will likely happen), high heels will be an obstacle, not an accessory."},{"tipo":"Mejor Hora","titulo":"Tarde de barrio","titulo_en":"Neighborhood afternoon","descripcion":"Visita el Museo de la Salsa entre las 14:00 y las 18:00, cuando Carlos Molina o sus herederos suelen estar atendiendo y colocando vinilos en el equipo de sonido. Esa es la experiencia completa: ver las fotos mientras suena la música original.","descripcion_en":"Visit the Salsa Museum between 2:00 PM and 6:00 PM, when Carlos Molina or his successors are usually there putting records on the sound system. That''s the full experience: seeing the photos while the original music plays."},{"tipo":"Bebida","titulo":"Aguapanela con limón","titulo_en":"Panela water with lemon","descripcion":"En el Barrio Obrero encontrarás tiendas de barrio tradicionales donde sirven aguapanela fría con limón — la bebida de los ensayos y los bailaderos populares de toda la vida. Es la hidratación auténtica de la ruta, no la lulada turística.","descripcion_en":"In Barrio Obrero you will find traditional corner stores serving cold panela water with lemon — the drink of rehearsals and popular dance venues for generations. It''s the authentic hydration of this route, not the tourist lulada."},{"tipo":"Foto","titulo":"Foto de la foto","titulo_en":"Photo of the photo","descripcion":"En el Museo de la Salsa, pregunta a Carlos Molina por las fotos de Celia Cruz en Cali (existen varias). La imagen dentro de la imagen — tú fotografiando esa historia — es una de las mejores que te llevarás de la ruta.","descripcion_en":"At the Salsa Museum, ask Carlos Molina for the photos of Celia Cruz in Cali (several exist). The image within the image — you photographing that history — is one of the best shots you''ll take on this route."}]'::jsonb,
  '[{"id":"chal-salsa-1","type":"TRIVIA","title":"El Origen Fotográfico","title_en":"The Photographic Origin","instruction":"Encuentra la fotografía más antigua de la sala principal del Museo de la Salsa y lee la fecha en la esquina inferior.","instruction_en":"Find the oldest photograph in the main hall of the Salsa Museum and read the date in the lower corner.","points_reward":150,"completed_message":"¡Has conectado con el origen visual de la salsa caleña!","completed_message_en":"You have connected with the visual origin of Cali salsa!","connection_story":"Estás en el Barrio Obrero, cuna del estilo caleño. Entra al Museo de la Salsa, fundado en 1968 por el fotógrafo Carlos Molina. Sus paredes guardan más de 40,000 fotografías analógicas de orquestas, bailadores y leyendas del sonido antillano que pasaron por Cali.","connection_story_en":"You are in Barrio Obrero, the cradle of the Cali style. Enter the Salsa Museum, founded in 1968 by photographer Carlos Molina. Its walls hold over 40,000 analog photographs of orchestras, dancers, and legends of the Antillean sound that passed through Cali.","quiz_data":{"question":"¿En qué año fundó Carlos Molina el Museo de la Salsa del Barrio Obrero?","question_en":"In what year did Carlos Molina found the Salsa Museum of Barrio Obrero?","options":["1955","1968","1975","1980"],"options_en":["1955","1968","1975","1980"],"correct_answer":"1968","correct_answer_en":"1968","fun_fact":"Carlos Molina inició la colección en su propia casa, guardando fotos y recortes de los espectáculos de salsa que llegaban a Juanchito y al Barrio Obrero.","fun_fact_en":"Carlos Molina started the collection in his own home, saving photos and press clippings of salsa shows that came to Juanchito and Barrio Obrero."}},{"id":"chal-salsa-2","type":"TRIVIA","title":"El Sonido de Niche en el Bronce","title_en":"The Sound of Niche in Bronze","instruction":"Párate dentro de una de las letras de la escultura N-I-C-H-E y escucha el sonido que produce el viento al pasar por las campanas. Luego responde.","instruction_en":"Stand inside one of the letters of the N-I-C-H-E sculpture and listen to the sound the wind makes as it passes through the bells. Then answer.","points_reward":150,"completed_message":"¡Has sentido la vibración del maestro Jairo Varela!","completed_message_en":"You have felt the vibration of maestro Jairo Varela!","connection_story":"Desde el Barrio Obrero, camina hacia el norte cruzando la Calle Quinta — el eje histórico de la Cali vieja — hasta la Plazoleta Jairo Varela frente al CAM. La escultura \"Niche\" de 8 metros de bronce fue diseñada para que el viento caleño la convierta en un instrumento de viento monumental.","connection_story_en":"From Barrio Obrero, walk north crossing Calle Quinta — the historic axis of old Cali — to the Plazoleta Jairo Varela in front of the CAM. The 8-meter bronze \"Niche\" sculpture was designed so the Cali breeze turns it into a monumental wind instrument.","quiz_data":{"question":"¿En qué año fue grabada \"Cali Pachanguero\", el himno más famoso del Grupo Niche?","question_en":"In what year was \"Cali Pachanguero\" recorded, Grupo Niche''s most famous anthem?","options":["1979","1984","1988","1992"],"options_en":["1979","1984","1988","1992"],"correct_answer":"1988","correct_answer_en":"1988","fun_fact":"\"Cali Pachanguero\" fue seleccionada por la FIFA como canción oficial del Mundial de Brasil 2014, llevando el nombre de Cali al planeta.","fun_fact_en":"\"Cali Pachanguero\" was selected by FIFA as an official song for the 2014 Brazil World Cup, carrying Cali''s name across the planet."}},{"id":"chal-salsa-3","type":"TRIVIA","title":"Memoria Sonora del Pacífico","title_en":"Pacific Sound Memory","instruction":"En la Audioteca Municipal, pide a un orientador que te muestre la colección de grabaciones de campo del Pacífico. Escucha al menos un fragmento de una grabación de los años 50 o 60.","instruction_en":"At the Municipal Audioteca, ask an advisor to show you the Pacific field recording collection. Listen to at least one excerpt from a 1950s or 60s recording.","points_reward":150,"completed_message":"¡Has preservado la memoria auditiva de un pueblo!","completed_message_en":"You have preserved the auditory memory of a people!","connection_story":"Cruza el Bulevar del Río y entra al Centro Cultural de Cali, la joya arquitectónica diseñada por Rogelio Salmona. En la planta baja encontrarás la Audioteca Municipal, un repositorio sonoro único que guarda grabaciones del Pacífico colombiano que no existen en ningún otro archivo del mundo.","connection_story_en":"Cross the River Boulevard and enter the Cali Cultural Center, the architectural jewel designed by Rogelio Salmona. On the ground floor you will find the Municipal Audioteca, a unique sound repository holding Colombian Pacific recordings that exist in no other archive in the world.","quiz_data":{"question":"¿Qué instrumento es el símbolo musical central de las comunidades afrocolombianas del Pacífico y fue declarado Patrimonio Inmaterial por la UNESCO en 2015?","question_en":"What instrument is the central musical symbol of Afro-Colombian Pacific communities and was declared Intangible Heritage by UNESCO in 2015?","options":["El Bongó","La Marimba de Chonta","El Tiple","La Guitarra Clásica"],"options_en":["The Bongo","The Chonta Marimba","The Tiple","The Classical Guitar"],"correct_answer":"La Marimba de Chonta","correct_answer_en":"The Chonta Marimba","fun_fact":"La marimba de chonta es fabricada con madera de palma de chonta y calabazas secas como resonadores. Cada marimba es única y lleva semanas construirla.","fun_fact_en":"The chonta marimba is made from chonta palm wood and dried gourds as resonators. Each marimba is unique and takes weeks to build."}}]'::jsonb,
  'badge-salsa',
  true,
  '00000000-0000-0000-0000-000000000000'
) ON CONFLICT (id) DO UPDATE SET
  nombre = EXCLUDED.nombre,
  nombre_en = EXCLUDED.nombre_en,
  puntos = EXCLUDED.puntos,
  duracion_min = EXCLUDED.duracion_min,
  descripcion = EXCLUDED.descripcion,
  descripcion_en = EXCLUDED.descripcion_en,
  intro_story = EXCLUDED.intro_story,
  intro_story_en = EXCLUDED.intro_story_en,
  justificaciones = EXCLUDED.justificaciones,
