  reward_badge_id,
  is_published,
  user_id
) VALUES (
  'ruta2',
  'Ruta Histórica y Colonial',
  'Historical and Colonial Route',
  '["s39","s12","s57","s2","s3","s19"]'::jsonb,
  180,
  'Esta ruta es un viaje en el tiempo hacia los cimientos mismos de Santiago de Cali. Caminar por el centro histórico es leer las páginas de la ''Sucursal del Cielo'' escritas en piedra y cal. Descubrirás la hidalguía de una ciudad que supo ser colonial, republicana y moderna sin perder su esencia. Desde la fe de sus templos hasta el poder de sus plazas, este recorrido es esencial para conectar con la memoria colectiva y entender cómo el pasado ha moldeado la sociedad caleña actual.

El itinerario te guiará por el corazón cívico en la Plaza de Cayzedo, pasando por la joya mudéjar de la Torre Mudéjar y la majestuosidad del Teatro Municipal. Cada fachada narra historias de independencia, arte y desarrollo. Visitarás el complejo religioso de San Francisco y La Merced, donde literalmente nació la ciudad, para luego conectar con el Río Cali, testigo silencioso de siglos de evolución.

Al finalizar, sentirás una profunda reverencia por el legado arquitectónico de Cali. Es una experiencia de contemplación y aprendizaje, ideal para ser combinada con un café tradicional en el Bulevar. Te llevarás no solo fotos de edificios hermosos, sino la comprensión de que Cali es una ciudad de capas, donde la historia sigue viva y dialogando con el presente.',
  'This route is a journey back in time to the very foundations of Santiago de Cali. Walking through the historic center is reading the pages of the ''Branch of Heaven'' written in stone and lime. You will discover the nobility of a city that managed to be colonial, republican, and modern without losing its essence. From the faith of its temples to the power of its squares, this tour is essential to connect with collective memory and understand how the past has shaped current Caleño society.

The itinerary will guide you through the civic heart at Plaza de Cayzedo, passing by the Mudejar jewel of the Mudejar Tower and the majesty of the Municipal Theater. Every facade tells stories of independence, art, and development. You will visit the religious complex of San Francisco and La Merced, where the city was literally born, to then connect with the Cali River, a silent witness to centuries of evolution.

By the end, you will feel a deep reverence for Cali''s architectural legacy. It is an experience of contemplation and learning, ideal to be combined with a traditional coffee on the Boulevard. You will take away not just photos of beautiful buildings, but the understanding that Cali is a city of layers, where history is still alive and dialoguing with the present.',
  'Bienvenido, viajero del tiempo. El reloj ha retrocedido 300 años. Tu misión es reconstruir la memoria perdida de Santiago de Cali. Debes encontrar los vestigios coloniales que sobrevivieron a la modernidad y escuchar lo que sus piedras tienen para decirte. ¿Podrás escuchar los susurros de la historia?',
  'Welcome, time traveler. The clock has turned back 300 years. Your mission is to reconstruct the lost memory of Santiago de Cali. You must find the colonial vestiges that survived modernity and listen to what their stones have to tell you. Can you hear the whispers of history?',
  '["El corazón cívico de la ciudad.","El edificio más antiguo de Cali (Siglo XVI).","La joya arquitectónica mudéjar única en el país.","Máximo escenario cultural de estilo republicano.","Conexión moderna con la historia del río.","Barrio fundacional con arquitectura colonial preservada."]'::jsonb,
  '["The civic heart of the city.","The oldest building in Cali (16th Century).","Unique Mudejar architectural jewel in the country.","Top cultural venue in Republican style.","Modern connection with the river''s history.","Foundational neighborhood with preserved colonial architecture."]'::jsonb,
  '[{"tipo":"Mejor Hora","tipo_en":"Best Time","titulo":"Mañana Temprano","titulo_en":"Early Morning","descripcion":"Inicia a las 9:00 AM para evitar el calor fuerte del mediodía.","descripcion_en":"Start at 9:00 AM to avoid the strong midday heat.","siteId":"s39"},{"tipo":"Snack","tipo_en":"Snack","titulo":"Pandebono Caliente","titulo_en":"Warm Pandebono","descripcion":"Imperdible comer un pandebono cerca a la Plaza de Cayzedo.","descripcion_en":"Must eat a pandebono near Plaza de Cayzedo.","siteId":"s39"},{"tipo":"Seguridad","tipo_en":"Safety","titulo":"Cuidado Personal","titulo_en":"Personal Care","descripcion":"Mantén tus pertenencias a la vista en zonas concurridas del centro.","descripcion_en":"Keep your belongings in sight in busy downtown areas.","siteId":"s3"}]'::jsonb,
  '[{"id":"chal-ruta2-0","type":"TRIVIA","title":"Desafío de Conocimiento","title_en":"Knowledge Challenge","instruction":"Responde correctamente para ganar puntos.","instruction_en":"Answer correctly to earn points.","points_reward":50,"completed_message":"¡Excelente! Has demostrado que conoces Cali.","completed_message_en":"Excellent! You proved you know Cali.","quiz_data":{"question":"¿Qué árboles característicos rodean la Plaza de Cayzedo?","question_en":"What characteristic trees surround Cayzedo Square?","options":["Robles","Palmas de Cera","Palmas Reales","Ceibas"],"options_en":["Oaks","Wax Palms","Royal Palms","Ceibas"],"correct_answer":"Palmas Reales","correct_answer_en":"Royal Palms","fun_fact":"Estas palmas son tan altas que se ven desde varios puntos del centro.","fun_fact_en":"These palms are so tall they can be seen from various points downtown."},"connection_story":"Bienvenido a la Ruta Histórica y Colonial. Iniciamos en el kilómetro cero de Cali: la Plaza de Cayzedo. Antigua Plaza Mayor, está rodeada por el Palacio Republicano de la Gobernación y el neoclásico Edificio Otero. Camina bajo sus imponentes palmas reales.","connection_story_en":"Welcome to the Historical and Colonial Route. We start at Cali''s mile zero: Plaza de Cayzedo. Formerly Plaza Mayor, it is surrounded by the Republican Palace of the Governorate and the neoclassical Otero Building. Walk under its towering royal palms."},{"id":"chal-ruta2-checkin-1","type":"CHECKIN","title":"Llegada al Sitio","title_en":"Site Arrival","instruction":"Acércate al punto para registrar tu visita.","instruction_en":"Get closer to the point to register your visit.","points_reward":30,"completed_message":"¡Has llegado! Visita registrada.","completed_message_en":"You arrived! Visit registered.","checkin_data":{"radius_meters":50},"allow_manual_trivia":true,"manual_trivia_data":{"question":"¿De qué color es la estatua de Joaquín de Cayzedo y Cuero?","question_en":"What color is the statue of Joaquín de Cayzedo y Cuero?","options":["Dorado","Bronce Oscuro","Blanco Mármol"],"options_en":["Golden","Dark Bronze","Marble White"],"correct_answer":"Bronce Oscuro","correct_answer_en":"Dark Bronze"},"connection_story":"Camina hacia el oeste por la calle 7, una de las vías coloniales más antiguas de la ciudad. A pocas cuadras, el concreto cede paso a las anchas paredes de adobe y arcos de piedra del Complejo Religioso de La Merced, el sitio exacto donde se celebró la primera misa de fundación de la ciudad el 25 de julio de 1536.","connection_story_en":"Walk west along Calle 7, one of the oldest colonial streets in the city. A few blocks away, concrete gives way to the thick adobe walls and stone arches of the La Merced Religious Complex, the exact site where the city''s first founding mass was celebrated on July 25, 1536."},{"id":"chal-ruta2-checkin-2","type":"CHECKIN","title":"Llegada al Sitio","title_en":"Site Arrival","instruction":"Acércate al punto para registrar tu visita.","instruction_en":"Get closer to the point to register your visit.","points_reward":30,"completed_message":"¡Has llegado! Visita registrada.","completed_message_en":"You arrived! Visit registered.","checkin_data":{"radius_meters":50},"connection_story":"Avanza hacia el sur por la Carrera 4, bordeando antiguas casonas coloniales con ventanas de reja de madera. Llegarás al Complejo Religioso de San Francisco, donde se alza la Torre Mudéjar. Esta estructura de ladrillo limpio del siglo XVIII, decorada con azulejos esmaltados y patrones geométricos de influencia morisca, es única en toda América.","connection_story_en":"Head south along Carrera 4, bordering old colonial houses with wooden grated windows. You will reach the San Francisco Religious Complex, where the Mudejar Tower stands. This 18th-century clean brick structure, decorated with glazed tiles and Moorish-influenced geometric patterns, is unique in the Americas."},{"id":"chal-ruta2-checkin-3","type":"CHECKIN","title":"Llegada al Sitio","title_en":"Site Arrival","instruction":"Acércate al punto para registrar tu visita.","instruction_en":"Get closer to the point to register your visit.","points_reward":30,"completed_message":"¡Has llegado! Visita registrada.","completed_message_en":"You arrived! Visit registered.","checkin_data":{"radius_meters":50},"connection_story":"Sigue por la Carrera 5 hacia la Calle 7. Te encontrarás en el sector del Teatro Municipal Enrique Buenaventura. Inaugurado en 1927 en la transición de la Cali republicana a la moderna, destaca por su fachada neoclásica francesa y su sala de ópera decorada con pinturas del italiano Mauricio Ramelli.","connection_story_en":"Continue along Carrera 5 towards Calle 7. You will find yourself in the sector of the Enrique Buenaventura Municipal Theater. Opened in 1927 during Cali''s transition from Republican to modern, it stands out for its French neoclassical facade and its opera hall decorated with paintings by Italian artist Mauricio Ramelli."},{"id":"chal-ruta2-checkin-4","type":"CHECKIN","title":"Llegada al Sitio","title_en":"Site Arrival","instruction":"Acércate al punto para registrar tu visita.","instruction_en":"Get closer to the point to register your visit.","points_reward":30,"completed_message":"¡Has llegado! Visita registrada.","completed_message_en":"You arrived! Visit registered.","checkin_data":{"radius_meters":50},"connection_story":"Dirígete hacia el río cruzando la Calle Quinta. Llegarás al Bulevar del Río, un espacio peatonal construido sobre un túnel subterráneo para disfrutar el viento de la tarde. A tu paso verás la Iglesia de la Ermita y el Puente Ortiz (1845), declarado monumento nacional por su ingeniería de ladrillo y cal.","connection_story_en":"Head towards the river crossing Calle Quinta. You will reach the River Boulevard, a pedestrian space built over an underground tunnel to enjoy the afternoon breeze. Along your path, you will see the Ermita Church and the Ortiz Bridge (1845), declared a national monument for its brick and lime engineering."},{"id":"chal-ruta2-checkin-5","type":"CHECKIN","title":"Llegada al Sitio","title_en":"Site Arrival","instruction":"Acércate al punto para registrar tu visita.","instruction_en":"Get closer to the point to register your visit.","points_reward":30,"completed_message":"¡Has llegado! Visita registrada.","completed_message_en":"You arrived! Visit registered.","checkin_data":{"radius_meters":50},"connection_story":"Cruza el río Cali hacia el oeste y adéntrate en las empinadas calles de piedra del barrio colonial de San Antonio. Sube la colina contemplando las casas de una sola planta con patios internos hasta llegar a la Capilla de San Antonio (1747), que corona la colina ofreciendo una panorámica inigualable de la ciudad.","connection_story_en":"Cross the Cali River to the west and venture into the steep stone streets of the colonial neighborhood of San Antonio. Climb the hill contemplating the single-story houses with internal courtyards until you reach the Chapel of San Antonio (1747), which crowns the hill offering an unparalleled panoramic view of the city."}]'::jsonb,
  NULL,
  true,
  '00000000-0000-0000-0000-000000000000'
) ON CONFLICT (id) DO UPDATE SET
  nombre = EXCLUDED.nombre,
  nombre_en = EXCLUDED.nombre_en,
  puntos = EXCLUDED.puntos,
  duracion_min = EXCLUDED.duracion_min,
