INSERT INTO public.routes (
  id,
  nombre,
  nombre_en,
  puntos,
  duracion_min,
  descripcion,
  descripcion_en,
  intro_story,
  intro_story_en,
  justificaciones,
  justificaciones_en,
  recomendaciones,
  gamificacion,
  reward_badge_id,
  is_published,
  user_id
) VALUES (
  'ruta3',
  'Pinceles de la Calle',
  'Brushes of the Street',
  '["muros-bulevar","puente-cerveceria","murales-siloe"]'::jsonb,
  150,
  'Las paredes de Cali no callan: gritan verdades a todo color. Desde el circuito de más de 2 km de murales sobre los muros de contención del río Cali en el Bulevar, pasando bajo el Puente de la Cervecería —cuyas columnas son lienzos monumentales de la historia industrial de la ciudad—, hasta los murales de la ladera de Siloé donde el arte comunitario transformó la narrativa de un barrio históricamente estigmatizado. Esta ruta es una lectura visual de la ciudad que no está en ningún libro: está pintada en sus muros.',
  'Cali''s walls don''t fall silent — they scream truths in full color. From the 2 km+ mural circuit on the flood control walls of the Cali River in the Bulevar, beneath the Puente de la Cervecería — whose columns are monumental canvases of the city''s industrial history — to the murals on Siloé''s hillside where community art transformed the narrative of a historically stigmatized neighborhood. This route is a visual reading of the city that appears in no book: it''s painted on its walls.',
  'Si las paredes hablaran, gritarían revolución. Pero aquí no hablan — pintan. El muralismo caleño no es decoración: es denuncia, memoria y orgullo. Antes de arrancar, mira el primer muro a tu izquierda cuando entres al Bulevar y pregúntate: ¿qué historia te está contando?',
  'If walls could talk, they would scream revolution. But here they don''t talk — they paint. Cali muralism is not decoration: it is denunciation, memory, and pride. Before starting, look at the first wall to your left when you enter the Bulevar and ask yourself: what story is it telling you?',
  '["El circuito de murales del Bulevar es uno de los más largos de América Latina: más de 2 km continuos.","El Puente de la Cervecería recuerda la primera industria moderna de Cali: la Cervecería Bavaria (1904).","Los murales de Siloé son un modelo internacional de arte comunitario que transformó la narrativa de un barrio."]'::jsonb,
  '["The Bulevar mural circuit is one of the longest in Latin America: over 2 continuous km.","The Cervecería Bridge recalls Cali''s first modern industry: Bavaria Brewery (1904).","The Siloé murals are an international model of community art that transformed a neighborhood''s narrative."]'::jsonb,
  '[{"tipo":"Mejor Hora","titulo":"Luz de la tarde para fotografiar","titulo_en":"Afternoon light for photography","descripcion":"Los murales del Bulevar y el Puente de la Cervecería tienen su mejor luz entre las 15:00 y las 17:30, cuando el sol del occidente ilumina de frente las paredes orientales. Los colores saturados y las sombras largas hacen fotos excepcionales en ese rango horario.","descripcion_en":"The Bulevar murals and Cervecería Bridge have their best light between 3:00 PM and 5:30 PM, when the western sun directly illuminates the eastern walls. Saturated colors and long shadows make exceptional photos in that time range."},{"tipo":"Transporte","titulo":"Bicicleta para el Bulevar, a pie para Siloé","titulo_en":"Bike for the Bulevar, on foot for Siloé","descripcion":"Para el Bulevar del Río, alquila una bicicleta de las estaciones de MiO Bici o Tembici — el circuito de murales se disfruta mejor en dos ruedas. Para Siloé, sube únicamente con un guía comunitario local (se consigue fácil por redes sociales de Ladera Cultura Viva) — ellos conocen los caminos seguros y la historia de cada mural.","descripcion_en":"For the Bulevar del Río, rent a bicycle from the MiO Bici or Tembici stations — the mural circuit is best enjoyed on two wheels. For Siloé, go only with a local community guide (easily found through Ladera Cultura Viva''s social media) — they know the safe paths and the story behind each mural."},{"tipo":"Experiencia","titulo":"Pregunta por el artista de cada mural","titulo_en":"Ask about the artist of each mural","descripcion":"En Siloé, los guías comunitarios saben quién pintó cada mural, cuándo lo hizo y qué historia quiso contar. Esa narrativa oral que acompaña a las imágenes es el 80% del valor del recorrido. Sin ella, son solo pinturas bonitas en una pared.","descripcion_en":"In Siloé, the community guides know who painted each mural, when they painted it, and what story they wanted to tell. That oral narrative accompanying the images is 80% of the tour''s value. Without it, they''re just pretty paintings on a wall."},{"tipo":"Foto","titulo":"El mural de las especies endémicas","titulo_en":"The endemic species mural","descripcion":"En el Bulevar del Río busca el mural de gran formato que representa al cóndor de los Andes y al pato careto — dos especies endémicas amenazadas del Valle del Cauca. El contraste entre la megafauna silvestre pintada y el río urbano detrás es visualmente poderoso.","descripcion_en":"On the Bulevar del Río look for the large-format mural representing the Andean condor and the pato careto — two threatened endemic species of Valle del Cauca. The contrast between the painted megafauna and the urban river behind is visually powerful."},{"tipo":"Seguridad","titulo":"Siloé: siempre con guía local","titulo_en":"Siloé: always with a local guide","descripcion":"El barrio Siloé tiene una comunidad vibrante y un programa de turismo comunitario sólido, pero es un barrio de ladera popular y el visitante que sube sin guía local puede desorientarse fácilmente. Contacta a Ladera Cultura Viva antes del recorrido: @laderacultureviva en Instagram.","descripcion_en":"Siloé has a vibrant community and a solid community tourism program, but it''s a popular hillside neighborhood and a visitor going up without a local guide can easily get disoriented. Contact Ladera Cultura Viva before the tour: @laderacultureviva on Instagram."}]'::jsonb,
  '[{"id":"chal-art-1","type":"TRIVIA","title":"El Río como Lienzo","title_en":"The River as Canvas","instruction":"Encuentra en los murales del Bulevar uno que represente fauna colombiana en peligro de extinción. Fotografíalo e identifica la especie retratada.","instruction_en":"Find in the Bulevar murals one representing endangered Colombian fauna. Photograph it and identify the species portrayed.","points_reward":150,"completed_message":"¡Has leído el primer capítulo del libro de paredes más largo de Cali!","completed_message_en":"You have read the first chapter of Cali''s longest wall book!","connection_story":"Estás ante el circuito de murales del Bulevar del Río Cali: más de 2 km de arte público continuo sobre los muros de contención del río. Las primeras intervenciones fueron ilegales, realizadas por colectivos de grafiti en los años 90. Hoy es una galería de arte oficial que renueva sus piezas cada año con el Festival de Arte Urbano de Cali (FAUC).","connection_story_en":"You are before the Bulevar del Río Cali mural circuit: over 2 km of continuous public art on the river''s retaining walls. The first interventions were illegal, made by graffiti collectives in the 1990s. Today it''s an official art gallery that renews its pieces annually with the Cali Urban Art Festival (FAUC).","quiz_data":{"question":"¿Cuántos kilómetros de extensión tiene el circuito de murales del Bulevar del Río Cali, convirtiéndolo en uno de los más largos de América Latina?","question_en":"How many kilometers long is the Bulevar del Río Cali mural circuit, making it one of the longest in Latin America?","options":["0.5 km","1 km","Más de 2 km","5 km"],"options_en":["0.5 km","1 km","More than 2 km","5 km"],"correct_answer":"Más de 2 km","correct_answer_en":"More than 2 km","fun_fact":"Durante el Festival FAUC, artistas de más de 20 países intervienen simultáneamente los muros de la ciudad durante una semana completa.","fun_fact_en":"During the FAUC Festival, artists from over 20 countries simultaneously work on the city''s walls for a full week."}},{"id":"chal-art-2","type":"TRIVIA","title":"Memoria Industrial en el Puente","title_en":"Industrial Memory on the Bridge","instruction":"Desde el Puente de la Cervecería, mira las garzas que anidan en los árboles del río Cali. Fotografíalas e identifica de qué especie se trata.","instruction_en":"From the Puente de la Cervecería, watch the herons nesting in the trees along the Cali River. Photograph them and identify the species.","points_reward":150,"completed_message":"¡Has visto la historia industrial de Cali desde el mejor mirador posible!","completed_message_en":"You have seen Cali''s industrial history from the best possible viewpoint!","connection_story":"El Puente de la Cervecería toma su nombre de la Cervecería Bavaria, fundada en este sector en 1904 — la primera industria moderna de Cali. Los galpones de ladrillo de Bavaria fueron demolidos en los años 80. Pero el nombre del puente permaneció como memoria popular, y sus columnas se convirtieron en lienzos monumentales del Festival FAUC.","connection_story_en":"The Puente de la Cervecería takes its name from the Bavaria Brewery, founded in this sector in 1904 — Cali''s first modern industry. The Bavaria brick buildings were demolished in the 1980s. But the bridge''s name remained as popular memory, and its columns became monumental canvases for the FAUC Festival.","quiz_data":{"question":"¿En qué año fue fundada la Cervecería Bavaria en Cali, la primera empresa en Colombia en producir cerveza industrial y refrigerada?","question_en":"In what year was the Bavaria Brewery founded in Cali, the first company in Colombia to produce industrial refrigerated beer?","options":["1880","1904","1920","1935"],"options_en":["1880","1904","1920","1935"],"correct_answer":"1904","correct_answer_en":"1904","fun_fact":"El mural más grande del Puente de la Cervecería mide 45 metros y fue pintado en una sola noche por un colectivo de artistas durante el FAUC 2019.","fun_fact_en":"The largest mural on the Cervecería Bridge is 45 meters long and was painted in a single night by an artist collective during FAUC 2019."}},{"id":"chal-art-3","type":"TRIVIA","title":"El Color que Transforma un Barrio","title_en":"The Color That Transforms a Neighborhood","instruction":"En los murales de Siloé, encuentra el mural que homenajea a los mineros de carbón y fotografíate junto a él.","instruction_en":"In the Siloé murals, find the mural honoring the coal miners and take a photo next to it.","points_reward":200,"completed_message":"¡Has subido a uno de los miradores de arte más poderosos de Cali!","completed_message_en":"You have climbed to one of Cali''s most powerful art viewpoints!","connection_story":"Siloé fue fundado en los años 20 por familias mineras que extraían carbón de la ladera occidental de Cali. Hasta los años 90, era considerado el barrio más peligroso de la ciudad. La organización Ladera Cultura Viva inició el proceso de transformación en 2010 a través de los murales y el turismo comunitario. Hoy es un destino cultural reconocido internacionalmente.","connection_story_en":"Siloé was founded in the 1920s by mining families who extracted coal from Cali''s western hillside. Until the 1990s, it was considered the city''s most dangerous neighborhood. The organization Ladera Cultura Viva began the transformation process in 2010 through murals and community tourism. Today it''s an internationally recognized cultural destination.","quiz_data":{"question":"¿En qué año comenzó el proceso de transformación cultural de Siloé a través del arte y el turismo comunitario impulsado por Ladera Cultura Viva?","question_en":"In what year did Siloé''s cultural transformation process through art and community tourism, driven by Ladera Cultura Viva, begin?","options":["1995","2003","2010","2018"],"options_en":["1995","2003","2010","2018"],"correct_answer":"2010","correct_answer_en":"2010","fun_fact":"Varios de los murales de Siloé fueron pintados por jóvenes que nunca habían tomado un pincel antes de ingresar al programa de arte de Ladera Cultura Viva.","fun_fact_en":"Several of Siloé''s murals were painted by young people who had never picked up a brush before joining the Ladera Cultura Viva art program."}}]'::jsonb,
  'badge-art',
  true,
  '00000000-0000-0000-0000-000000000000'
) ON CONFLICT (id) DO UPDATE SET
  nombre = EXCLUDED.nombre,
  nombre_en = EXCLUDED.nombre_en,
  puntos = EXCLUDED.puntos,
  duracion_min = EXCLUDED.duracion_min,
  descripcion = EXCLUDED.descripcion,
  descripcion_en = EXCLUDED.descripcion_en,
  intro_story = EXCLUDED.intro_story,
  intro_story_en = EXCLUDED.intro_story_en,
  justificaciones = EXCLUDED.justificaciones,
  justificaciones_en = EXCLUDED.justificaciones_en,
  recomendaciones = EXCLUDED.recomendaciones,
  gamificacion = EXCLUDED.gamificacion,
  reward_badge_id = EXCLUDED.reward_badge_id,
  is_published = EXCLUDED.is_published;

INSERT INTO public.routes (
  id,
  nombre,
  nombre_en,
  puntos,
  duracion_min,
  descripcion,
  descripcion_en,
  intro_story,
  intro_story_en,
