  recomendaciones,
  gamificacion,
  reward_badge_id,
  is_published,
  user_id
) VALUES (
  'ruta4',
  'Ruta de la Naturaleza Urbana',
  'Urban Nature Route',
  '["s20","s30","s65","s5"]'::jsonb,
  300,
  'Cali es un ''privilegio verde'' abrazado por la cordillera de los Farallones. Esta ruta es un escape vital y necesario para reconectar con la tierra sin salir de la urbe. ''La Ruta de la Naturaleza Urbana'' te ofrece un respiro del asfalto, llevándote a través de los pulmones que oxigenan la ciudad. Es una travesía de salud mental y física, diseñada para quienes entienden que la verdadera riqueza de Cali reside en su exuberante biodiversidad y sus paisajes imponentes.

Experimentarás una transición ecológica fascinante: desde la frescura cristalina del Río Pance, el balneario natural por excelencia de los caleños, hasta el bosque seco tropical conservado en el Jardín Botánico y el Zoológico. El desafío físico llega con el ascenso al Cerro de las Tres Cruces, un ritual deportivo local que premia el esfuerzo con la mejor vista panorámica del Valle del Cauca. Es un recorrido donde el canto de las aves reemplaza al ruido del tráfico.

Terminarás este recorrido renovado, con los pulmones llenos de aire puro y la retina cargada de los atardeceres más famosos de Colombia. Esta ruta te recordará por qué Cali es una potencia mundial de avistamiento de aves y naturaleza. Es una invitación a sudar, a respirar profundo y a sentir la energía vital de una ciudad que florece todo el año.',
  'Cali is a ''green privilege'' embraced by the Farallones mountain range. This route is a vital and necessary escape to reconnect with the earth without leaving the city. ''The Urban Nature Route'' offers you a respite from the asphalt, taking you through the lungs that oxygenate the city. It is a journey of mental and physical health, designed for those who understand that Cali''s true wealth lies in its exuberant biodiversity and imposing landscapes.

You will experience a fascinating ecological transition: from the crystalline freshness of the Pance River, the natural spa par excellence of the Caleños, to the tropical dry forest preserved in the Botanical Garden and the Zoo. The physical challenge comes with the ascent to the Hill of the Three Crosses, a local sports ritual that rewards effort with the best panoramic view of the Valle del Cauca. It is a tour where the song of birds replaces traffic noise.

You will finish this tour renewed, lungs full of fresh air and eyes loaded with Colombia''s most famous sunsets. This route will remind you why Cali is a world power in bird watching and nature. It is an invitation to sweat, breathe deep, and feel the vital energy of a city that blooms all year round.',
  NULL,
  NULL,
  '["El balneario natural de los caleños.","Conocimiento sobre la biodiversidad local.","Reto físico y la mejor vista de la ciudad.","Atardecer con brisa y vista al valle."]'::jsonb,
  '["The natural spa of the Caleños.","Knowledge about local biodiversity.","Physical challenge and the best view of the city.","Sunset with breeze and valley view."]'::jsonb,
  '[{"tipo":"Vestuario","tipo_en":"Attire","titulo":"Deportivo","titulo_en":"Sporty","descripcion":"Ropa ligera, tenis de agarre y gorra son obligatorios.","descripcion_en":"Light clothing, grip sneakers, and a cap are mandatory.","siteId":"s65"},{"tipo":"Salud","tipo_en":"Health","titulo":"Protección Solar","titulo_en":"Sun Protection","descripcion":"El sol de Cali es fuerte, usa bloqueador solar.","descripcion_en":"Cali''s sun is strong, use sunscreen.","siteId":"s20"},{"tipo":"Horario","tipo_en":"Schedule","titulo":"Amanecer","titulo_en":"Sunrise","descripcion":"Para las Tres Cruces, sube antes de las 7:00 AM.","descripcion_en":"For Tres Cruces, climb before 7:00 AM.","siteId":"s65"}]'::jsonb,
  '[{"id":"chal-ruta4-checkin-0","type":"CHECKIN","title":"Llegada al Sitio","title_en":"Site Arrival","instruction":"Acércate al punto para registrar tu visita.","instruction_en":"Get closer to the point to register your visit.","points_reward":30,"completed_message":"¡Has llegado! Visita registrada.","completed_message_en":"You arrived! Visit registered.","checkin_data":{"radius_meters":50},"allow_manual_trivia":true,"manual_trivia_data":{"question":"En el río Pance, ¿qué actividad es más popular los domingos?","question_en":"What activity is most popular at Pance River on Sundays?","options":["Pesca Deportiva","Sancocho de Olla","Surf"],"options_en":["Sport Fishing","Pot Stew (Sancocho)","Surfing"],"correct_answer":"Sancocho de Olla","correct_answer_en":"Pot Stew (Sancocho)"},"connection_story":"Bienvenido a la Ruta de la Naturaleza Urbana. Iniciamos en el sur de Cali, en el Ecoparque Río Pance. Este es el balneario natural tradicional de los caleños, donde la vegetación de submontaña y las aguas frías que bajan directamente de los Farallones ofrecen un respiro natural.","connection_story_en":"Welcome to the Urban Nature Route. We start in southern Cali, at the Pance River Ecopark. This is the traditional natural spa of the Caleños, where sub-mountain vegetation and cold waters flowing directly from the Farallones offer a natural escape."},{"id":"chal-ruta4-checkin-1","type":"CHECKIN","title":"Llegada al Sitio","title_en":"Site Arrival","instruction":"Acércate al punto para registrar tu visita.","instruction_en":"Get closer to the point to register your visit.","points_reward":30,"completed_message":"¡Has llegado! Visita registrada.","completed_message_en":"You arrived! Visit registered.","checkin_data":{"radius_meters":50},"connection_story":"Nos desplazamos hacia el oeste buscando la cuenca media del río Cali. Cruzarás la Avenida Circunvalar para llegar al Jardín Botánico de Cali. Ubicado en el cañón del río Cali, este espacio conserva 14 hectáreas de bosque seco tropical, un ecosistema altamente amenazado, y cuenta con un sendero de plantas y estaciones de conservación.","connection_story_en":"We move towards the west seeking the middle basin of the Cali River. You will cross Avenida Circunvalar to reach the Cali Botanical Garden. Located in the Cali River canyon, this space preserves 14 hectares of tropical dry forest, a highly threatened ecosystem, and features a plant trail and conservation stations."},{"id":"chal-ruta4-checkin-2","type":"CHECKIN","title":"Llegada al Sitio","title_en":"Site Arrival","instruction":"Acércate al punto para registrar tu visita.","instruction_en":"Get closer to the point to register your visit.","points_reward":30,"completed_message":"¡Has llegado! Visita registrada.","completed_message_en":"You arrived! Visit registered.","checkin_data":{"radius_meters":50},"connection_story":"Siguiendo el cauce del río Cali hacia el oeste por la Avenida Fluvial, llegarás al Zoológico de Cali, uno de los mejores de América Latina. Se destaca por sus programas de conservación de especies andinas y del Pacífico colombiano, y sus senderos rodeados de árboles centenarios y aguas corrientes.","connection_story_en":"Following the path of the Cali River west along Avenida Fluvial, you will reach the Cali Zoo, one of the best in Latin America. It stands out for its conservation programs of Andean and Colombian Pacific species, and its trails surrounded by century-old trees and flowing waters."},{"id":"chal-ruta4-checkin-3","type":"CHECKIN","title":"Llegada al Sitio","title_en":"Site Arrival","instruction":"Acércate al punto para registrar tu visita.","instruction_en":"Get closer to the point to register your visit.","points_reward":30,"completed_message":"¡Has llegado! Visita registrada.","completed_message_en":"You arrived! Visit registered.","checkin_data":{"radius_meters":50},"connection_story":"Prepárate para un ascenso físico de tradición local. Cruzarás hacia el norte de la ciudad buscando el pie de monte en el barrio Normandía. Ascenderás el Cerro de las Tres Cruces a través de un sendero empinado rodeado de vegetación xerófila. El esfuerzo de subir este hito religioso y deportivo te premiará con la mejor panorámica del Valle del Cauca.","connection_story_en":"Prepare for a physical climb of local tradition. You will cross to the north of the city seeking the foot of the hill in the Normandía neighborhood. You will ascend the Hill of the Three Crosses through a steep path surrounded by xerophytic vegetation. The effort of climbing this religious and sporting landmark will reward you with the best panoramic view of the Cauca Valley."}]'::jsonb,
  NULL,
  true,
  '00000000-0000-0000-0000-000000000000'
) ON CONFLICT (id) DO UPDATE SET
  nombre = EXCLUDED.nombre,
  nombre_en = EXCLUDED.nombre_en,
  puntos = EXCLUDED.puntos,
  duracion_min = EXCLUDED.duracion_min,
  descripcion = EXCLUDED.descripcion,
