INSERT INTO public.routes (
  id,
  nombre,
  nombre_en,
  puntos,
  duracion_min,
  descripcion,
  descripcion_en,
  intro_story,
  intro_story_en,
  justificaciones,
  justificaciones_en,
  recomendaciones,
  gamificacion,
  reward_badge_id,
  is_published,
  user_id
) VALUES (
  'ruta5',
  'Cali de Papel',
  'Cali on Paper',
  '["teatro-municipal","edificio-otero","biblioteca-centenario"]'::jsonb,
  120,
  'Adéntrate en las páginas vivas de la Cali de los años 70, la época del movimiento "Caliwood" y la efervescencia literaria de Andrés Caicedo. Siguiendo los pasos de una generación de escritores, directores y soñadores que hicieron de la ciudad su musa y su campo de batalla, esta ruta explora los rincones del centro histórico que inspiraron historias de cine, locura y juventud. El Teatro Municipal donde Buenaventura inventó un nuevo teatro latinoamericano. El Edificio Otero que vio pasar a García Márquez. La Biblioteca Centenario donde reposan los manuscritos de Jorge Isaacs. Cali no se escribe, se vive — pero aquí aprenderás a leerla.',
  'Venture into the living pages of 1970s Cali, the era of the "Caliwood" movement and the literary fervor of Andrés Caicedo. Following the footsteps of a generation of writers, directors, and dreamers who made the city their muse and battlefield, this route explores the corners of the historic center that inspired stories of film, madness, and youth. The Municipal Theater where Buenaventura invented a new Latin American theater. The Otero Building that saw García Márquez pass through. The Centenario Library where Jorge Isaacs'' manuscripts rest.',
  'Cali es una ciudad que espera, pero que no le abre la puerta a los desesperados. Lo escribió Andrés Caicedo antes de morir a los 25 años, con "¡Qué viva la música!" recién publicada. Hoy caminarás por la ciudad que él amó y odió en partes iguales, y entenderás por qué esa tensión la convirtió en literatura.',
  'Cali is a city that waits, but doesn''t open its door to the desperate. Andrés Caicedo wrote this before dying at 25, with "¡Qué viva la música!" just published. Today you will walk through the city he loved and hated in equal parts, and understand why that tension turned it into literature.',
  '["Enrique Buenaventura y el TEC inventaron el teatro moderno colombiano en el Teatro Municipal.","\"Caliwood\" fue uno de los movimientos cinematográficos más influyentes de América Latina del siglo XX.","La Biblioteca Centenario guarda los únicos manuscritos originales de Jorge Isaacs en Colombia."]'::jsonb,
  '[]'::jsonb,
  '[{"tipo":"Experiencia","titulo":"Lee antes de caminar","titulo_en":"Read before walking","descripcion":"Si no has leído \"¡Qué viva la música!\" de Andrés Caicedo, lee aunque sea el primer capítulo antes de esta ruta. El libro está ambientado en los mismos sectores que vas a caminar y lo convierte en una experiencia de lectura viva.","descripcion_en":"If you haven''t read Andrés Caicedo''s \"¡Qué viva la música!\", read at least the first chapter before this route. The book is set in the same sectors you''ll walk and turns it into a living reading experience."},{"tipo":"Mejor Hora","titulo":"Mañana para leer, tarde para el teatro","titulo_en":"Morning for reading, afternoon for theater","descripcion":"La Biblioteca Centenario y sus archivos históricos son más accesibles en la mañana, cuando hay personal que puede orientar la consulta. Deja el Teatro Municipal para la tarde — si hay ensayo o visita guiada programada, podrás entrar a la sala principal.","descripcion_en":"Centenario Library and its historical archives are more accessible in the morning, when staff are available to guide consultations. Leave the Municipal Theater for the afternoon — if there''s a rehearsal or scheduled guided tour, you can enter the main hall."},{"tipo":"Foto","titulo":"La sala de la ópera","titulo_en":"The opera hall","descripcion":"Si logras entrar al Teatro Municipal Enrique Buenaventura, fotografía el plafón central: los frescos al temple del italiano Mauricio Ramelli con escenas de la Divina Comedia son los únicos de autoría italiana republicana en Colombia.","descripcion_en":"If you manage to enter the Enrique Buenaventura Municipal Theater, photograph the central ceiling: the tempera frescoes by Italian artist Mauricio Ramelli with scenes from the Divine Comedy are the only ones of Italian Republican authorship in Colombia."},{"tipo":"Planificación","titulo":"Consulta la cartelera del Teatro Municipal","titulo_en":"Check the Municipal Theater schedule","descripcion":"Revisa en redes sociales del Teatro Municipal (@teatromunicipalcali) si hay función ese día. Ver una obra en ese escenario — aunque sea un ensayo de la Escuela de Bellas Artes — es el cierre perfecto para esta ruta literaria.","descripcion_en":"Check the Municipal Theater''s social media (@teatromunicipalcali) if there''s a show that day. Seeing a performance at that venue — even a rehearsal from the Bellas Artes school — is the perfect close for this literary route."}]'::jsonb,
  '[{"id":"chal-lit-1","type":"TRIVIA","title":"El Teatro que Inventó un Método","title_en":"The Theater That Invented a Method","instruction":"Frente al Teatro Municipal Enrique Buenaventura, fotografía la fachada neoclásica y cuenta los pisos y las columnas que la componen.","instruction_en":"In front of the Enrique Buenaventura Municipal Theater, photograph the neoclassical facade and count the floors and columns that compose it.","points_reward":150,"completed_message":"¡Estás parado frente a la joya máxima de la escena colombiana!","completed_message_en":"You are standing in front of the crown jewel of Colombian theater!","connection_story":"El Teatro Municipal Enrique Buenaventura fue inaugurado en 1927 con la ópera \"Aida\" de Verdi, interpretada por una compañía italiana traída exclusivamente para la ocasión. Su fachada neoclásica y su sala en herradura lo convierten en el único teatro de la región con capacidad técnica para producir ópera completa.","connection_story_en":"The Enrique Buenaventura Municipal Theater was inaugurated in 1927 with Verdi''s opera \"Aida\", performed by an Italian company brought exclusively for the occasion. Its neoclassical facade and horseshoe hall make it the only theater in the region technically capable of producing full opera.","quiz_data":{"question":"¿En qué año fue inaugurado el Teatro Municipal Enrique Buenaventura de Cali y con qué ópera?","question_en":"In what year was the Enrique Buenaventura Municipal Theater of Cali inaugurated and with what opera?","options":["1910 con Carmen","1927 con Aida","1935 con La Traviata","1945 con Madama Butterfly"],"options_en":["1910 with Carmen","1927 with Aida","1935 with La Traviata","1945 with Madama Butterfly"],"correct_answer":"1927 con Aida","correct_answer_en":"1927 with Aida","fun_fact":"Los frescos del plafón del teatro son obra del pintor italiano Mauricio Ramelli y representan escenas de la Divina Comedia de Dante. Son los únicos de ese tipo en Colombia.","fun_fact_en":"The theater''s ceiling frescoes are by Italian painter Mauricio Ramelli and represent scenes from Dante''s Divine Comedy. They are the only ones of that type in Colombia."}},{"id":"chal-lit-2","type":"TRIVIA","title":"El Hotel de los Famosos","title_en":"The Hotel of the Famous","instruction":"Observa con detención la fachada del Edificio Otero sobre la Plaza de Cayzedo. Cuenta los detalles ornamentales de yeso: guirnaldas, pilastras, medallones.","instruction_en":"Carefully observe the facade of the Otero Building on Plaza de Cayzedo. Count the plaster ornamental details: garlands, pilasters, medallions.","points_reward":150,"completed_message":"¡Has leído la fachada más elegante del centro histórico de Cali!","completed_message_en":"You have read the most elegant facade in Cali''s historic center!","connection_story":"El Edificio Otero, construido en 1926 sobre una esquina de la Plaza de Cayzedo, albergó en su época dorada el Hotel Europa — el más lujoso de Cali. Por sus habitaciones pasaron figuras como García Márquez en sus visitas a la ciudad en los años 50. Hoy es uno de los pocos inmuebles republicanos del centro que conserva su volumetría original intacta.","connection_story_en":"The Otero Building, built in 1926 on a corner of Plaza de Cayzedo, housed in its golden era the Hotel Europa — the most luxurious in Cali. Figures like García Márquez passed through its rooms during his city visits in the 1950s. Today it''s one of the few Republican buildings in the center preserving its original volume intact.","quiz_data":{"question":"¿Qué importante escritor colombiano fue uno de los huéspedes del Hotel Europa, que funcionó en el Edificio Otero?","question_en":"What important Colombian writer was one of the guests at Hotel Europa, which operated in the Otero Building?","options":["Jorge Isaacs","Gabriel García Márquez","Tomás González","Álvaro Mutis"],"options_en":["Jorge Isaacs","Gabriel García Márquez","Tomás González","Álvaro Mutis"],"correct_answer":"Gabriel García Márquez","correct_answer_en":"Gabriel García Márquez","fun_fact":"La Plaza de Cayzedo, frente al Edificio Otero, es el kilómetro cero de Cali: todas las distancias de la ciudad se miden desde este punto.","fun_fact_en":"Plaza de Cayzedo, in front of the Otero Building, is Cali''s kilometer zero: all distances in the city are measured from this point."}},{"id":"chal-lit-3","type":"TRIVIA","title":"El Manuscrito del Valle","title_en":"The Manuscript of the Valley","instruction":"En la Biblioteca Centenario, pide al personal que te muestre la sección de fondos históricos o el archivo de Jorge Isaacs. Fotografía un documento histórico (con permiso del personal).","instruction_en":"At Centenario Library, ask the staff to show you the historical collections section or the Jorge Isaacs archive. Photograph a historical document (with staff permission).","points_reward":200,"completed_message":"¡Has tocado la memoria literaria escrita más antigua de Cali!","completed_message_en":"You have touched Cali''s oldest written literary memory!","connection_story":"La Biblioteca Centenario fue inaugurada en 1910 para conmemorar el primer siglo de la Independencia de Colombia. En sus fondos históricos reposan manuscritos originales de Jorge Isaacs — el autor de \"María\", la novela más importante del romanticismo latinoamericano — junto con documentos que datan de 1875.","connection_story_en":"Centenario Library was inaugurated in 1910 to commemorate the first century of Colombia''s Independence. In its historical collections rest original manuscripts by Jorge Isaacs — author of \"María\", the most important novel of Latin American Romanticism — along with documents dating from 1875.","quiz_data":{"question":"¿En qué año fue publicada \"María\" de Jorge Isaacs, la novela más importante del romanticismo latinoamericano, ambientada en las haciendas del Valle del Cauca?","question_en":"In what year was Jorge Isaacs'' \"María\" published, the most important novel of Latin American Romanticism, set in the Valle del Cauca haciendas?","options":["1845","1867","1890","1910"],"options_en":["1845","1867","1890","1910"],"correct_answer":"1867","correct_answer_en":"1867","fun_fact":"\"María\" fue el primer best-seller latinoamericano: se agotó en pocas semanas en Colombia y fue traducida al francés en 1876, convirtiéndose en una de las primeras novelas latinoamericanas publicadas en Europa.","fun_fact_en":"\"María\" was Latin America''s first best-seller: it sold out in weeks in Colombia and was translated into French in 1876, becoming one of the first Latin American novels published in Europe."}}]'::jsonb,
  'badge-lit',
  true,
  '00000000-0000-0000-0000-000000000000'
) ON CONFLICT (id) DO UPDATE SET
  nombre = EXCLUDED.nombre,
